/**
 * Modular exponentiation: (base^exp) % mod
 * Uses BigInt to safely handle intermediate products up to (mod-1)^2 when mod is large.
 * @param {number} base 
 * @param {number} exp 
 * @param {number} mod 
 * @returns {number} (base^exp) % mod
 */
function power(base, exp, mod) {
    let res = 1n;
    base = BigInt(base) % BigInt(mod);
    exp = BigInt(exp);
    mod = BigInt(mod);

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return Number(res);
}

/**
 * @param {number[]} nums1
 * @param {number[]} nums0
 * @returns {number}
 */
function solve(nums1, nums0) {
    const MOD = 1000000007;
    const N = nums1.length;

    // 1. Create segment objects
    const segments = [];
    for (let i = 0; i < N; i++) {
        segments.push({
            n1: nums1[i],
            n0: nums0[i],
            length: nums1[i] + nums0[i]
        });
    }

    // 2. Sort segments using custom comparison logic
    // We prefer segment A over segment B if S_A S_B >= S_B S_A lexicographically.
    segments.sort((A, B) => {
        // Primary comparison: More leading ones (n1) means higher value. Sort descending by n1.
        if (A.n1 !== B.n1) {
            return B.n1 - A.n1;
        }

        // Secondary comparison: If n1 are equal, less trailing zeros (n0) means higher value. Sort ascending by n0.
        if (A.n0 !== B.n0) {
            return A.n0 - B.n0;
        }

        return 0; // Equal order
    });

    // 3. Calculate total value V mod MOD

    let totalValue = 0;
    let suffixLength = 0;

    // Iterate through the sorted segments in reverse order (from rightmost to leftmost)
    for (let k = N - 1; k >= 0; k--) {
        const { n1, n0, length } = segments[k];

        // Calculate V_k = 2^n0 * (2^n1 - 1) mod MOD

        // 2^n1 mod MOD
        const pow2_n1 = power(2, n1, MOD);

        // (2^n1 - 1) mod MOD
        // Ensure result is positive before multiplication
        const term1 = (pow2_n1 - 1 + MOD) % MOD; 

        // 2^n0 mod MOD
        const pow2_n0 = power(2, n0, MOD);

        // V_k = pow2_n0 * term1 mod MOD
        const Vk = (BigInt(pow2_n0) * BigInt(term1)) % BigInt(MOD);
        const Vk_num = Number(Vk);

        // Calculate 2^E_k mod MOD, where E_k = suffixLength
        const pow2_Ek = power(2, suffixLength, MOD);

        // Contribution = V_k * 2^E_k mod MOD
        const contribution = (BigInt(Vk_num) * BigInt(pow2_Ek)) % BigInt(MOD);

        // Add to total value
        totalValue = (totalValue + Number(contribution)) % MOD;

        // Update suffix length for the next segment (k-1)
        suffixLength += length;
    }

    return totalValue;
}

